const { test, expect } = require('@playwright/test');

test('Verify header navigation links on mobile', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002');

  // Verify Home (brand okwasniewski) link
  const homeLink = page.locator('a:has-text("okwasniewski")').first();
  await expect(homeLink).toBeVisible();
  await homeLink.click();
  await expect(page).toHaveURL('http://localhost:3002/');

  // Verify Blog link
  const blogLink = page.locator('a:has-text("blog")').first();
  await expect(blogLink).toBeVisible();
  await blogLink.click();
  await expect(page).toHaveURL(/.*\/blog/);

  // Verify Portfolio link
  const portfolioLink = page.locator('a:has-text("portfolio")').first();
  await expect(portfolioLink).toBeVisible();
  await portfolioLink.click();
  await expect(page).toHaveURL(/.*\/portfolio/);

  // Verify Videos link
  const videosLink = page.locator('a:has-text("videos")').first();
  await expect(videosLink).toBeVisible();
  await videosLink.click();
  await expect(page).toHaveURL(/.*\/videos/);

  // Verify Contact link (Fails - routes to /contcat)
  const contactLink = page.locator('a:has-text("contact")').first();
  await expect(contactLink).toBeVisible();
  await contactLink.click();
  await expect(page).toHaveURL(/.*\/contact/);
});
